-- ============================================================
-- 导入重庆IT企业到 companies 表
-- 数据源: 顺企网 (shunqi.com)
-- 数量: 2207 条
-- ============================================================

ALTER TABLE companies ADD COLUMN IF NOT EXISTS business_scope TEXT;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS city TEXT;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS province TEXT;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS established DATE;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS contact TEXT;

-- 确保 name 唯一约束（幂等）
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname='companies_name_key') THEN ALTER TABLE companies ADD CONSTRAINT companies_name_key UNIQUE (name); END IF; END $$;


-- 验证
SELECT count(*) AS imported FROM companies WHERE province='重庆' AND city='重庆';